namespace sv_7acf052ae1634c308d8a7bbad54fcae1.Services;

public sealed class Recipe
{
    public int Id { get; init; }
    public string Title { get; init; } = string.Empty;
    public string Description { get; init; } = string.Empty;
    public int PrepTimeMinutes { get; init; }
}

public interface IRecipeService
{
    Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken);
}

public sealed class RecipeService : IRecipeService
{
    private static readonly Dictionary<int, List<Recipe>> _data = new()
    {
        [1] = new List<Recipe>
        {
            new() { Id = 1, Title = "Margherita Pizza", Description = "Classic Neapolitan pizza with fresh mozzarella, basil, and San Marzano tomatoes.", PrepTimeMinutes = 45 },
            new() { Id = 2, Title = "Spaghetti Carbonara", Description = "Traditional Roman pasta with guanciale, egg yolk, pecorino, and black pepper.", PrepTimeMinutes = 25 },
            new() { Id = 3, Title = "Tiramisu", Description = "Layered dessert with espresso-soaked ladyfingers and mascarpone cream.", PrepTimeMinutes = 30 },
        },
        [2] = new List<Recipe>
        {
            new() { Id = 4, Title = "Pad Thai", Description = "Stir-fried rice noodles with shrimp, peanuts, bean sprouts, and tamarind sauce.", PrepTimeMinutes = 35 },
            new() { Id = 5, Title = "Green Curry", Description = "Aromatic coconut curry with Thai basil, bamboo shoots, and chicken.", PrepTimeMinutes = 40 },
            new() { Id = 6, Title = "Tom Yum Soup", Description = "Hot and sour soup with lemongrass, galangal, kaffir lime leaves, and prawns.", PrepTimeMinutes = 20 },
        },
        [3] = new List<Recipe>
        {
            new() { Id = 7, Title = "Tacos al Pastor", Description = "Marinated pork tacos with pineapple, cilantro, and onion on corn tortillas.", PrepTimeMinutes = 60 },
            new() { Id = 8, Title = "Guacamole", Description = "Fresh avocado dip with lime, jalapeño, tomato, and cilantro.", PrepTimeMinutes = 10 },
            new() { Id = 9, Title = "Enchiladas Verdes", Description = "Corn tortillas filled with chicken, topped with tangy tomatillo salsa verde.", PrepTimeMinutes = 50 },
        },
    };

    public async Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken)
    {
        // Simulate slow API call
        await Task.Delay(2000, cancellationToken);

        if (_data.TryGetValue(cuisineId, out var recipes))
        {
            return recipes;
        }

        return new List<Recipe>();
    }
}

@page "/recipes/{CuisineId:int}"
@rendermode InteractiveServer
@using sv_7acf052ae1634c308d8a7bbad54fcae1.Services
@using Microsoft.AspNetCore.Components.Routing
@implements IDisposable
@inject IRecipeService RecipeService
@inject ILogger<Recipes> Logger
@inject NavigationManager Navigation

<PageTitle>Recipes</PageTitle>

<h1>Recipes</h1>

<nav style="margin-bottom: 1rem;">
    <a href="/recipes/1">Italian</a> |
    <a href="/recipes/2">Thai</a> |
    <a href="/recipes/3">Mexican</a>
</nav>

@if (_error is not null)
{
    <div class="alert alert-danger" role="alert">
        <p>@_error</p>
        <button class="btn btn-outline-danger" @onclick="Retry">Retry</button>
    </div>
}
else if (_recipes is null)
{
    <p><em>Loading recipes...</em></p>
}
else
{
    @if (_isRefreshing)
    {
        <p><em>Refreshing…</em></p>
    }

    <ul>
        @foreach (var recipe in _displayedRecipes)
        {
            <li>
                <strong>@recipe.Title</strong> — @recipe.Description
                <br /><small>Prep time: @recipe.PrepTimeMinutes min</small>
            </li>
        }
    </ul>
}

@code {
    [Parameter] public int CuisineId { get; set; }
    [SupplyParameterFromQuery(Name = "sort")] public string? Sort { get; set; }

    private List<Recipe>? _recipes;
    private string? _error;
    private bool _isRefreshing;
    private int _loadedCuisineId;
    private CancellationTokenSource? _cts;

    private IEnumerable<Recipe> _displayedRecipes =>
        string.Equals(Sort, "popular", StringComparison.OrdinalIgnoreCase)
            ? _recipes!.OrderBy(r => r.PrepTimeMinutes)
            : _recipes!.OrderByDescending(r => r.Id);

    protected override async Task OnParametersSetAsync()
    {
        // Only reload if cuisine actually changed
        if (CuisineId == _loadedCuisineId && _recipes is not null)
            return;

        await LoadRecipesAsync();
    }

    private async Task LoadRecipesAsync()
    {
        // Cancel any in-flight request
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = new CancellationTokenSource();
        var token = _cts.Token;

        _error = null;

        if (_recipes is not null)
        {
            _isRefreshing = true;
        }

        try
        {
            var results = await RecipeService.GetByCuisineAsync(CuisineId, token);

            // Check cancellation after await in case a race occurred
            token.ThrowIfCancellationRequested();

            _recipes = results;
            _loadedCuisineId = CuisineId;
            _isRefreshing = false;
        }
        catch (OperationCanceledException) when (token.IsCancellationRequested)
        {
            // Request was superseded or component is disposing — do nothing
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout loading recipes for cuisine {CuisineId}", CuisineId);
            _isRefreshing = false;
            _error = "The request timed out. Please try again.";
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Error loading recipes for cuisine {CuisineId}", CuisineId);
            _isRefreshing = false;
            _error = "Something went wrong loading recipes. Please try again.";
        }
    }

    private async Task Retry()
    {
        await LoadRecipesAsync();
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

